  ('optometrist-moex-00224', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於隱形眼鏡引起之乳突結膜炎，下列敘述何者錯誤？', '["軟式隱形眼鏡中，矽水膠材質較傳統水膠材質不易引起", "乳突大多出現在上眼瞼結膜", "形成原因中，也可能與瞼板線功能異常有關", "隱形眼鏡停戴後，需1至2週，乳突就會消失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00225', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起的併發症角膜上皮微囊（epithelialmicrocyst）之敘述，下列何者錯誤？', '["因缺氧引起細胞有絲分裂速率變快，導致細胞的殘留物和不正常細胞的成長", "配戴持續配戴型（extendedwearcontactlens）的軟式隱形眼鏡比日戴型隱形眼鏡（dailywearcontactlens） 更容易發生", "上皮細胞（epithelialcell）因長期缺氧造成細胞代謝能力下降引起", "可能對隱形眼鏡護理液的防腐劑產生的過敏反應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00226', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴軟式隱形眼鏡引起的基質層條紋（stromalstriate）併發症之敘述，下列何者最正確？', '["基質層（stromal）產生的條紋（striate）見於高傳氧性（Dk/t）的矽水膠隱形眼鏡之配戴者", "基質層條紋（stromalstriate）的產生與隱形眼鏡的透氧性（Dk）完全無關", "基質層條紋常出現在後基質層上", "因配戴軟式隱形眼鏡機械性摩擦引起基質層條紋的產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
